/* ── Favourites (localStorage) ───────────────────────────────── */
/* Event delegation — capture phase so we fire BEFORE the article onclick */
document.addEventListener('click', function(e) {
    const btn = e.target.closest('.prop-heart');
    if (!btn) return;
    e.stopPropagation(); /* stops article onclick from firing */
    e.preventDefault();
    const id = String(btn.dataset.id);
    const stored = JSON.parse(localStorage.getItem(COP_FAV_KEY) || '{}');
    try {
        const p = JSON.parse(decodeURIComponent(escape(atob(btn.dataset.prop))));
        if (COP_FAVS.has(id)) {
            COP_FAVS.delete(id);
            delete stored[id];
            btn.classList.remove('active');
        } else {
            COP_FAVS.add(id);
            stored[id] = { id:p.id, title:p.title, url:p.url, img:p.img, country:p.country,
                region:p.region, city:p.city, beds:p.beds, size:p.size, price:p.price,
                currency:p.currency, status:p.status, label:p.label };
            btn.classList.add('active');
        }
        localStorage.setItem(COP_FAV_KEY, JSON.stringify(stored));
        updateFavCount();
    } catch(err) { console.error('Fav error', err); }
}, true); /* true = capture phase, fires before article onclick */

function updateFavCount() {
    const n = COP_FAVS.size;
    document.querySelectorAll('.cop-fav-count').forEach(el => {
        el.textContent = n > 0 ? n : '';
        el.style.display = n > 0 ? 'inline-flex' : 'none';
    });
}
updateFavCount();
